const record = $input.first().json.record ?? $input.first().json;
const phaseLabels = {
  onboarding: 'Démarrage du projet',
  design: 'Phase design & maquettes',
  dev: 'Développement en cours',
  recette: 'Validation & recette',
  livraison: 'Mise en ligne',
  maintenance: 'Maintenance & support'
};
const phaseDescriptions = {
  onboarding: "Nous collectons toutes les informations nécessaires pour démarrer.",
  design: "Nos designers créent les maquettes de votre site. Votre validation sera demandée.",
  dev: "Notre équipe technique développe votre site. Nous vous tiendrons informé de l'avancement.",
  recette: "Votre site est presque prêt ! Nous préparons la phase de validation finale.",
  livraison: "Votre site est en ligne ! Vérifiez que tout fonctionne correctement.",
  maintenance: "Votre site est en production. Notre équipe assure sa maintenance."
};
return [{
  json: {
    projectId: record.project_id,
    phase: record.phase,
    phaseLabel: phaseLabels[record.phase] ?? record.phase,
    phaseDescription: phaseDescriptions[record.phase] ?? '',
    note: record.note ?? ''
  }
}];
